class Solution:
    def maximumSubarrayXor(self, nums, queries):
        # Independent implementation: literally simulate the fold-and-drop
        # process on every candidate subarray instead of using the recurrence.
        def xor_score(arr):
            a = list(arr)
            while len(a) > 1:
                a = [a[i] ^ a[i + 1] for i in range(len(a) - 1)]
            return a[0]

        res = []
        for l, r in queries:
            best = 0
            for i in range(l, r + 1):
                for j in range(i, r + 1):
                    best = max(best, xor_score(nums[i:j + 1]))
            res.append(best)
        return res

