var maximumSubarrayXor = function(nums, queries) {
    const n = nums.length;
    const score = Array.from({length: n}, () => new Array(n).fill(0));
    const best = Array.from({length: n}, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) { score[i][i] = nums[i]; best[i][i] = nums[i]; }
    for (let len = 2; len <= n; len++) {
        for (let l = 0; l + len - 1 < n; l++) {
            const r = l + len - 1;
            score[l][r] = score[l][r - 1] ^ score[l + 1][r];
            best[l][r] = Math.max(score[l][r], best[l + 1][r], best[l][r - 1]);
        }
    }
    return queries.map(([l, r]) => best[l][r]);
};
